import { useState, useRef, useMemo, useCallback, useEffect } from "react";

/* ─── SUPABASE CONFIG ─────────────────────────────────────────
   When you are ready to deploy:
   1. Go to https://supabase.com → New project
   2. Settings → API → copy Project URL and anon public key
   3. Authentication → Providers → enable Google / Apple / LinkedIn
   4. Replace the two placeholder strings below with your real values
   The app works fully with local auth until you do this.
─────────────────────────────────────────────────────────────── */
const SUPABASE_URL  = "https://YOUR_PROJECT_ID.supabase.co";
const SUPABASE_ANON = "YOUR_ANON_KEY";
const SB_CONFIGURED = !SUPABASE_URL.includes("YOUR_PROJECT");

// Supabase client — loaded dynamically so the artifact always works
let _sb = null;
async function getSB() {
  if (_sb) return _sb;
  if (!SB_CONFIGURED) return null;
  return new Promise((resolve) => {
    if (window.__supabase) { _sb = window.__supabase.createClient(SUPABASE_URL, SUPABASE_ANON); resolve(_sb); return; }
    const s = document.createElement("script");
    s.src = "https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2/dist/umd/supabase.js";
    s.onload  = () => { _sb = window.supabase.createClient(SUPABASE_URL, SUPABASE_ANON); resolve(_sb); };
    s.onerror = () => resolve(null);
    document.head.appendChild(s);
  });
}

// Normalise a Supabase user → app user shape
function sbUserToApp(u) {
  if (!u) return null;
  const m = u.user_metadata || {};
  return {
    id: u.id, email: u.email,
    name:       m.name       || m.full_name || u.email.split("@")[0],
    level:      m.level      || "",
    cvUploaded: m.cvUploaded || false,
    cvName:     m.cvName     || "",
    cvText:     m.cvText     || "",
    photoUrl:   m.photoUrl   || m.avatar_url || "",
    location:   m.location   || "",
  };
}

// ── Local (in-memory) auth — used when Supabase is not configured
const MEM_USERS = {};
function localSignUp(name, email, pw, level) {
  if (MEM_USERS[email]) return { error: "An account with this email already exists." };
  const u = { id: email, email, name, level, pw };
  MEM_USERS[email] = u;
  return { user: { id: email, email, user_metadata: { name, level } } };
}
function localSignIn(email, pw) {
  const u = MEM_USERS[email];
  if (!u || u.pw !== pw) return { error: "Incorrect email or password." };
  return { user: { id: email, email, user_metadata: { name: u.name, level: u.level } } };
}

