/* ─── THEME ─────────────────────────────────────────────────── */
function useTheme() {
  const [dark, setDark] = useState(false);
  const t = dark
    ? { bg:"#0C0C0E", surface:"#18181B", card:"#1C1C1F", border:"#27272A",
        text:"#FAFAFA", muted:"#71717A", sub:"#A1A1AA",
        inputBg:"#27272A", nav:"rgba(12,12,14,0.96)", shadow:"rgba(0,0,0,0.7)" }
    : { bg:"#F9F9FB", surface:"#F4F4F6", card:"#FFFFFF", border:"#E4E4E7",
        text:"#18181B", muted:"#71717A", sub:"#52525B",
        inputBg:"#FFFFFF", nav:"rgba(249,249,251,0.96)", shadow:"rgba(0,0,0,0.06)" };
  return { dark, setDark, t };
}

