/* ─── UTILS ─────────────────────────────────────────────────── */
// Tracker data is stored in memory per session
const TRACKER_MEM = {};
const LS = {
  get: k => { try { return TRACKER_MEM[k] !== undefined ? JSON.parse(TRACKER_MEM[k]) : null; } catch { return null; } },
  set: (k,v) => { try { TRACKER_MEM[k] = JSON.stringify(v); } catch {} },
};
function pwStrength(pw) {
  if (!pw) return { score:0, label:"", color:"transparent" };
  let s=0;
  if (pw.length>=8) s++; if (pw.length>=12) s++;
  if (/[A-Z]/.test(pw)) s++; if (/[a-z]/.test(pw)) s++;
  if (/[0-9]/.test(pw)) s++; if (/[^A-Za-z0-9]/.test(pw)) s++;
  if (s<=2) return { score:s, label:"Weak", color:"#EF4444" };
  if (s<=4) return { score:s, label:"Moderate", color:"#F59E0B" };
  return { score:s, label:"Strong", color:"#10B981" };
}

