                  <button onClick={()=>setTab("Scholarships")} style={{padding:"11px 20px",background:"transparent",color:t.muted,border:`1.5px solid ${t.border}`,borderRadius:11,fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Scholarships</button>
