/* ─── JOBS ───────────────────────────────────────────────────── */
const ALL_AREAS=["All","Corporate & Commercial","Banking & Finance","Compliance","ADR / Dispute Resolution","Human Rights","IP Law","Tech & Emerging Law","Oil & Gas","Labour Law","Real Estate","Tax Law","Maritime Law","Private Client"];

function JobsTab({ user, t }) {
  const [lv,setLv]=useState(user?.level==="experienced"?"Exp":"Entry");
  const [filters,setFilters]=useState({q:"",area:"All",type:"All"});
  const filtered=useMemo(()=>JOBS.filter(j=>{
    if(j.lv!==lv) return false;
    if(filters.area!=="All"&&j.area!==filters.area) return false;
    if(filters.type!=="All"&&j.type!==filters.type) return false;
    if(filters.q){const q=filters.q.toLowerCase();return j.title.toLowerCase().includes(q)||j.co.toLowerCase().includes(q)||j.area.toLowerCase().includes(q)||j.loc.toLowerCase().includes(q);}
    return true;
  }),[lv,filters]);
  const [ready,setReady]=useState(false);
  useEffect(()=>{const t=setTimeout(()=>setReady(true),120);return()=>clearTimeout(t);},[]);
  if(!ready) return <TabSkeleton t={t}/>;
  return (
    <div style={{paddingBottom:80}}>
      <SectionHead title="Job Board" sub={`${filtered.length} ${lv==="Entry"?"entry-level":"experienced"} roles curated for Nigerian legal professionals.`}/>
      <div style={{background:t.card,border:`1px solid ${t.border}`,borderRadius:14,padding:16,marginBottom:18}}>
        <div style={{display:"flex",gap:7,marginBottom:14}}>
          {[["Entry","Entry Level / NYSC / Fresh Graduate"],["Exp","Experienced Lawyer"]].map(([v,l])=><button key={v} onClick={()=>setLv(v)} style={{flex:1,padding:"9px 0",fontSize:13,fontWeight:700,border:`1.5px solid ${lv===v?CR:t.border}`,borderRadius:9,cursor:"pointer",fontFamily:"inherit",background:lv===v?CR:"transparent",color:lv===v?"#fff":t.muted}}>{l}</button>)}
        </div>
        <FilterPanel filters={filters} setFilters={setFilters} areas={ALL_AREAS} t={t}/>
      </div>
      {filtered.length===0&&<EmptyState title="No roles found" sub="Try a different search term or adjust the filters." t={t}/>}
      <div style={{display:"flex",flexDirection:"column",gap:8}}>{filtered.map(j=><ExpandCard key={j.id} job={j} t={t}/>)}</div>
    </div>
  );
}

/* ─── INTERNSHIPS ────────────────────────────────────────────── */
function InternshipsTab({ t }) {
  const areas=["All",...new Set(INTERNSHIPS.map(i=>i.area))];
  const [filters,setFilters]=useState({q:"",area:"All",type:"All",paid:"All"});
  const filtered=useMemo(()=>INTERNSHIPS.filter(i=>{
    if(filters.type!=="All"&&i.type!==filters.type) return false;
    if(filters.paid!=="All"){if(filters.paid==="Paid"&&!i.paid)return false;if(filters.paid==="Unpaid"&&i.paid)return false;}
    if(filters.area!=="All"&&i.area!==filters.area) return false;
    if(filters.q){const q=filters.q.toLowerCase();return i.title.toLowerCase().includes(q)||i.org.toLowerCase().includes(q);}
    return true;
  }),[filters]);
  return (
    <div style={{paddingBottom:80}}>
      <SectionHead title="Internships" sub={`${filtered.length} curated opportunities — local and international, paid and unpaid.`}/>
      <div style={{background:t.card,border:`1px solid ${t.border}`,borderRadius:14,padding:16,marginBottom:18}}>
        <FilterPanel filters={filters} setFilters={setFilters} areas={areas} t={t} showPaid/>
      </div>
      {filtered.length===0&&<EmptyState title="No internships found" sub="Try adjusting your filters or clearing the search." t={t}/>}
      <div style={{display:"flex",flexDirection:"column",gap:8}}>{filtered.map(j=><ExpandCard key={j.id} job={j} t={t}/>)}</div>
    </div>
  );
}

/* ─── SCHOLARSHIPS ───────────────────────────────────────────── */
function ScholarshipsTab({ t }) {
  const countries=["All",...new Set(SCHOLARSHIPS.map(s=>s.country))];
  const [filters,setFilters]=useState({q:"",area:"All",type:"All",funded:"All"});
  const [deg,setDeg]=useState("All");
  const [country,setCountry]=useState("All");
  const filtered=useMemo(()=>SCHOLARSHIPS.filter(s=>{
    if(deg!=="All"&&!s.deg.includes(deg)) return false;
    if(country!=="All"&&!s.country.includes(country)) return false;
    if(filters.funded!=="All"){if(filters.funded==="Fully Funded"&&!s.funded)return false;if(filters.funded==="Partial"&&s.funded)return false;}
    if(filters.q){const q=filters.q.toLowerCase();if(!s.name.toLowerCase().includes(q)&&!s.inst.toLowerCase().includes(q)&&!s.country.toLowerCase().includes(q)) return false;}
    return true;
  }),[deg,country,filters]);
  return (
    <div style={{paddingBottom:80}}>
      <SectionHead title="Scholarships" sub={`${filtered.length} LLM and PhD funding opportunities updated for 2026.`}/>
      <div style={{background:t.card,border:`1px solid ${t.border}`,borderRadius:14,padding:16,marginBottom:18}}>
        <FilterPanel filters={filters} setFilters={setFilters} t={t} showFunded/>
        <div style={{display:"flex",gap:6,flexWrap:"wrap",marginTop:12}}>
          {["All","LLM","PhD"].map(v=><button key={v} onClick={()=>setDeg(v)} style={{padding:"4px 12px",fontSize:12,fontWeight:600,border:`1.5px solid ${deg===v?CR:t.border}`,borderRadius:16,cursor:"pointer",fontFamily:"inherit",background:deg===v?`${CR}15`:"transparent",color:deg===v?CR:t.muted}}>{v}</button>)}
          <div style={{width:1,background:t.border,margin:"0 2px"}}/>
          {countries.map(c=><button key={c} onClick={()=>setCountry(c)} style={{padding:"4px 12px",fontSize:12,fontWeight:600,border:`1.5px solid ${country===c?CR:t.border}`,borderRadius:16,cursor:"pointer",fontFamily:"inherit",background:country===c?`${CR}15`:"transparent",color:country===c?CR:t.muted}}>{c}</button>)}
        </div>
      </div>
      {filtered.length===0&&<EmptyState title="No scholarships found" sub="Try clearing the degree or country filter." t={t}/>}
      <div style={{display:"flex",flexDirection:"column",gap:8}}>{filtered.map(s=><ExpandCard key={s.id} job={s} t={t}/>)}</div>
    </div>
  );
}

/* ─── APPLICATION TRACKER ────────────────────────────────────── */
const ST={Applied:{c:"#2563EB",bg:"#EFF6FF",dot:"#2563EB",label:"Applied"},Interview:{c:"#D97706",bg:"#FFFBEB",dot:"#D97706",label:"Interview"},Offer:{c:"#059669",bg:"#ECFDF5",dot:"#059669",label:"Offer"},Rejected:{c:"#DC2626",bg:"#FEF2F2",dot:"#DC2626",label:"Rejected"},Pending:{c:"#6B7280",bg:"#F9FAFB",dot:"#9CA3AF",label:"Pending"}};

function TrackerTab({ user, t }) {
  const uid=user?.id||"guest";
  const [apps,setApps]=useState(()=>LS.get("esq_apps_"+uid)||[]);
  const [showAdd,setShowAdd]=useState(false);
  const [f,setF]=useState({company:"",role:"",type:"Remote",date:new Date().toISOString().slice(0,10),status:"Applied",notes:""});
  const [stF,setStF]=useState("All");
  const sf=(k,v)=>setF(p=>({...p,[k]:v}));
  const inp={width:"100%",padding:"10px 12px",borderRadius:9,border:`1.5px solid ${t.border}`,fontSize:13,outline:"none",background:t.inputBg,color:t.text,fontFamily:"inherit",boxSizing:"border-box"};
  const add=()=>{
    if(!f.company||!f.role) return;
    const u=[{...f,id:Date.now()},...apps]; setApps(u); LS.set("esq_apps_"+uid,u);
    setF({company:"",role:"",type:"Remote",date:new Date().toISOString().slice(0,10),status:"Applied",notes:""}); setShowAdd(false);
  };
  const upd=(id,status)=>{const u=apps.map(a=>a.id===id?{...a,status}:a);setApps(u);LS.set("esq_apps_"+uid,u);};
  const del=(id)=>{const u=apps.filter(a=>a.id!==id);setApps(u);LS.set("esq_apps_"+uid,u);};
  const filtered=stF==="All"?apps:apps.filter(a=>a.status===stF);
  const counts=Object.keys(ST).reduce((acc,s)=>({...acc,[s]:apps.filter(a=>a.status===s).length}),{});
  return (
    <div style={{paddingBottom:80}}>
      <SectionHead title="Application Tracker" sub="Monitor every application, interview and offer in one place."/>
      <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:8,marginBottom:18}}>
        {Object.entries(ST).map(([k,v])=>(
          <div key={k} onClick={()=>setStF(stF===k?"All":k)} style={{background:stF===k?v.bg:t.card,border:`1px solid ${stF===k?v.c+"40":t.border}`,borderRadius:12,padding:"12px 8px",textAlign:"center",cursor:"pointer",transition:"all 0.15s"}}>
            <div style={{width:7,height:7,borderRadius:"50%",background:v.dot,margin:"0 auto 5px"}}/>
            <div style={{fontSize:"clamp(16px,3vw,22px)",fontWeight:900,color:v.c}}>{counts[k]||0}</div>
            <div style={{fontSize:10,color:v.c,fontWeight:700,marginTop:1}}>{k}</div>
          </div>
        ))}
      </div>
      <button onClick={()=>setShowAdd(o=>!o)} style={{width:"100%",padding:"12px 0",background:showAdd?t.surface:`linear-gradient(135deg,${CR},${CRV})`,color:showAdd?t.muted:"#fff",border:showAdd?`1.5px solid ${t.border}`:"none",borderRadius:11,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit",marginBottom:12}}>
        {showAdd?"Cancel":"+ Log New Application"}
      </button>
      {showAdd&&(
        <Card t={t} style={{padding:"18px 16px",marginBottom:14}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div style={{gridColumn:"1/-1"}}><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Company</div><input style={inp} placeholder="e.g. Access Bank" value={f.company} onChange={e=>sf("company",e.target.value)}/></div>
            <div style={{gridColumn:"1/-1"}}><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Role</div><input style={inp} placeholder="e.g. Legal Officer" value={f.role} onChange={e=>sf("role",e.target.value)}/></div>
            <div><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Type</div><select value={f.type} onChange={e=>sf("type",e.target.value)} style={inp}>{["Remote","Hybrid","Onsite"].map(v=><option key={v}>{v}</option>)}</select></div>
            <div><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Date Applied</div><input type="date" style={inp} value={f.date} onChange={e=>sf("date",e.target.value)}/></div>
            <div style={{gridColumn:"1/-1"}}><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Notes</div><input style={inp} placeholder="e.g. Applied via LinkedIn..." value={f.notes} onChange={e=>sf("notes",e.target.value)}/></div>
          </div>
          <button onClick={add} style={{width:"100%",marginTop:12,padding:"11px 0",background:`linear-gradient(135deg,${CR},${CRV})`,color:"#fff",border:"none",borderRadius:9,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>Save Application</button>
        </Card>
      )}
      <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:14}}>
        {["All",...Object.keys(ST)].map(s=><button key={s} onClick={()=>setStF(s)} style={{padding:"5px 12px",fontSize:11,fontWeight:600,border:`1.5px solid ${stF===s?(ST[s]?.c||CR):t.border}`,borderRadius:16,cursor:"pointer",fontFamily:"inherit",background:stF===s?`${ST[s]?.c||CR}15`:"transparent",color:stF===s?(ST[s]?.c||CR):t.muted}}>{s}</button>)}
      </div>
      {filtered.length===0&&(apps.length===0
  ? <EmptyState title="Nothing tracked yet" sub="Hit '+ Log New Application' above to start monitoring your job search." t={t}/>
  : <EmptyState title="No matches" sub="No applications in this status category." t={t}/>
)}
      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {filtered.map(app=>{
          const st=ST[app.status]||ST.Pending;
          return (
            <Card key={app.id} t={t} style={{padding:"14px 16px"}}>
              <div style={{display:"flex",gap:10,alignItems:"flex-start"}}>
                <div style={{width:9,height:9,borderRadius:"50%",background:st.dot,marginTop:4,flexShrink:0}}/>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontWeight:700,fontSize:13,color:t.text,marginBottom:2}}>{app.role}</div>
                  <div style={{fontSize:12,color:t.muted,marginBottom:5}}>{app.company} &middot; {app.type} &middot; {app.date}</div>
                  {app.notes&&<div style={{fontSize:12,color:t.sub,background:t.surface,borderRadius:7,padding:"5px 9px",marginBottom:7}}>{app.notes}</div>}
                  <div style={{display:"flex",gap:4,flexWrap:"wrap",alignItems:"center"}}>
                    {Object.keys(ST).map(s=><button key={s} onClick={()=>upd(app.id,s)} style={{padding:"2px 8px",fontSize:11,fontWeight:app.status===s?800:500,border:`1px solid ${app.status===s?ST[s].c:t.border}`,borderRadius:12,cursor:"pointer",fontFamily:"inherit",background:app.status===s?ST[s].bg:"transparent",color:app.status===s?ST[s].c:t.muted}}>{ST[s].label}</button>)}
                    <button onClick={()=>del(app.id)} style={{marginLeft:"auto",padding:"2px 8px",fontSize:11,background:"#FEF2F2",color:CRL,border:"none",borderRadius:12,cursor:"pointer",fontFamily:"inherit",fontWeight:600,display:"flex",alignItems:"center",gap:3}}><Ic n="trash" s={10} c={CRL}/>Delete</button>
                  </div>
                </div>
              </div>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

/* ─── AI CALL ────────────────────────────────────────────────── */
async function callClaude(sys, msg) {
  try {
    const res = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "anthropic-version": "2023-06-01",
        "anthropic-dangerous-direct-browser-access": "true",
      },
      body: JSON.stringify({
        model: "claude-sonnet-4-20250514",
        max_tokens: 1200,
        system: sys,
        messages: [{ role: "user", content: msg }],
      }),
    });
    if (!res.ok) {
      const err = await res.json().catch(()=>({}));
      return "Error: " + (err?.error?.message || `HTTP ${res.status}`);
    }
    const d = await res.json();
    return (d.content || []).filter(b => b.type === "text").map(b => b.text).join("\n");
  } catch (e) {
    return "Error: " + e.message;
  }
}

/* ─── COVER LETTER ───────────────────────────────────────────── */
function CoverLetterTab({ user, t }) {
  const [f,setF]=useState({name:user?.name||"",role:"",co:"",type:"Remote",skills:"",extra:""});
  const [result,setResult]=useState("");
  const [loading,setLoading]=useState(false);
  const [copied,setCopied]=useState(false);
  const [error,setError]=useState("");
  const set=(k,v)=>setF(p=>({...p,[k]:v}));
  const inp={width:"100%",padding:"11px 13px",borderRadius:9,border:`1.5px solid ${t.border}`,fontSize:13,outline:"none",background:t.inputBg,color:t.text,fontFamily:"inherit",boxSizing:"border-box"};
  const go=async()=>{
    if(!f.name||!f.role||!f.co) return;
    setLoading(true);setResult("");setError("");
    const cvCtx=user.cvText?`\n\nApplicant CV:\n${user.cvText.slice(0,1500)}`:"";
    const r=await callClaude(
      "You are an expert career coach for Nigerian law professionals. Write a compelling, professional cover letter for the Nigerian legal market. Warm, confident, specific. Max 340 words. Include today's date, a proper addressee and formal sign-off. No placeholders. No hyphens or em dashes.",
      `Name: ${f.name}\nRole: ${f.role}\nOrganisation: ${f.co}\nWork mode: ${f.type}\nKey skills: ${f.skills||"legal research, drafting, advocacy"}\nContext: ${f.extra||"legal professional eager to contribute"}${cvCtx}`
    );
    if(r.startsWith("Error")||r.startsWith("Unable")) setError(r); else setResult(r);
    setLoading(false);
  };
  const copy=()=>{navigator.clipboard.writeText(result);setCopied(true);setTimeout(()=>setCopied(false),2000);};
  return (
    <div style={{paddingBottom:80}}>
      <SectionHead title="Cover Letter Generator" sub={user.cvText?"AI uses your uploaded CV to personalise your letter.":"AI-crafted, role-specific cover letters in seconds."}/>
      {user.cvUploaded&&<div style={{background:"#ECFDF5",border:"1px solid #059669",borderRadius:10,padding:"10px 14px",marginBottom:16,fontSize:12,color:"#065F46",display:"flex",alignItems:"center",gap:6}}><Ic n="check" s={13} c="#059669"/> CV uploaded: {user.cvName} — your letter will be personalised using it.</div>}

      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(280px,1fr))",gap:24}}>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          {[["Full Name","name","Adaeze Okonkwo"],["Job Title","role","Legal Associate"],["Organisation","co","Human Rights Watch Nigeria"]].map(([lb,k,ph])=>(
            <div key={k}><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>{lb}</div><input style={inp} placeholder={ph} value={f[k]} onChange={e=>set(k,e.target.value)}/></div>
          ))}
          <div><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Work Mode</div><div style={{display:"flex",gap:6}}>{["Remote","Hybrid","Onsite"].map(v=><button key={v} onClick={()=>set("type",v)} style={{flex:1,padding:"9px 0",fontSize:12,fontWeight:700,border:`1.5px solid ${f.type===v?CR:t.border}`,borderRadius:9,cursor:"pointer",fontFamily:"inherit",background:f.type===v?CR:"transparent",color:f.type===v?"#fff":t.muted}}>{v}</button>)}</div></div>
          <div><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Key Skills</div><input style={inp} placeholder="e.g. contract drafting, negotiation, ADR" value={f.skills} onChange={e=>set("skills",e.target.value)}/></div>
          <div><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Additional Context</div><textarea value={f.extra} onChange={e=>set("extra",e.target.value)} placeholder="NYSC experience, languages, awards..." rows={3} style={{...inp,resize:"vertical"}}/></div>
          <button onClick={go} disabled={loading||!f.name||!f.role||!f.co} style={{padding:"12px 0",background:loading||!f.name||!f.role||!f.co?t.border:`linear-gradient(135deg,${CR},${CRV})`,color:"#fff",border:"none",borderRadius:11,fontSize:13,fontWeight:700,cursor:loading||!f.name||!f.role||!f.co?"not-allowed":"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:7}}>
            <Ic n="spark" s={15} c="#fff"/>{loading?"Writing your letter...":"Generate Cover Letter"}
          </button>
          {error&&<div style={{fontSize:12,color:t.sub,background:t.surface,borderRadius:8,padding:"12px 14px",lineHeight:1.6,borderLeft:`3px solid ${CR}`}}>{error}</div>}
        </div>
        <div>
          {!result&&!loading&&<div style={{background:t.surface,border:`2px dashed ${t.border}`,borderRadius:14,minHeight:380,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",color:t.muted,textAlign:"center",padding:24}}><Ic n="pen" s={32} c={t.border} style={{marginBottom:12}}/><p style={{fontSize:13,lineHeight:1.7}}>Fill in your details and click Generate. Your personalised cover letter will appear here.</p></div>}
          {loading&&<div style={{background:t.surface,border:`1px solid ${t.border}`,borderRadius:14,minHeight:380,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",color:t.muted}}><Logo size={40}/><p style={{fontSize:13,marginTop:10}}>Crafting your letter...</p></div>}
          {result&&!loading&&<>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
              <span style={{fontWeight:700,fontSize:13,color:t.text}}>Your Cover Letter</span>
              <button onClick={copy} style={{padding:"6px 12px",background:copied?"#059669":"transparent",color:copied?"#fff":CR,border:`1.5px solid ${copied?"#059669":CR}`,borderRadius:7,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",gap:5}}><Ic n={copied?"check":"copy"} s={12} c={copied?"#fff":CR}/>{copied?"Copied":"Copy"}</button>
            </div>
            <div style={{background:t.card,border:`1px solid ${t.border}`,borderRadius:12,padding:"20px 18px",fontSize:13,lineHeight:1.85,color:t.text,whiteSpace:"pre-wrap",fontFamily:"'Georgia',serif",maxHeight:580,overflowY:"auto"}}>{result}</div>
          </>}
        </div>
      </div>
    </div>
  );
}

/* ─── CV REVAMP ─────────────────────────────────────────────── */
function CVRevampTab({ user, t, updateUser }) {
  const [cv,setCv]=useState(user.cvText||"");
  const [fn,setFn]=useState(user.cvName||"");
  const [result,setResult]=useState("");
  const [loading,setLoading]=useState(false);
  const [target,setTarget]=useState("");
  const [error,setError]=useState("");
  const ref=useRef();
  const inp={width:"100%",padding:"11px 13px",borderRadius:9,border:`1.5px solid ${t.border}`,fontSize:13,outline:"none",background:t.inputBg,color:t.text,fontFamily:"inherit",boxSizing:"border-box"};
  const handleFile=e=>{
    const file=e.target.files[0]; if(!file) return; setFn(file.name);
    const r=new FileReader();
    if(file.type==="application/pdf"){
      r.onload=ev=>{
        const raw=ev.target.result;
        const textMatch=raw.match(/\(([^)]{2,})\)/g);
        let extracted=textMatch?textMatch.map(p=>p.slice(1,-1)).join(" ").replace(/\s+/g," ").trim():"";
        const text=extracted.length>80?extracted:`[PDF uploaded: ${file.name}. The browser extracted limited text from this PDF. For best results, paste your CV text below.]`;
        setCv(text); updateUser({...user,cvUploaded:true,cvName:file.name,cvText:text});
      };
      r.readAsBinaryString(file);
    } else {
      r.onload=ev=>{setCv(ev.target.result);updateUser({...user,cvUploaded:true,cvName:file.name,cvText:ev.target.result});};
      r.readAsText(file);
    }
  };
  const go=async()=>{
    if(!cv.trim()) return;
    setLoading(true);setResult("");setError("");
    const r=await callClaude(
      "You are a professional CV editor for Nigerian law professionals. Rewrite the CV: clean, impactful, ATS-friendly, strong action verbs. Sections: Personal Information, Professional Summary, Education, Work Experience, Skills, Certifications. Output only the rewritten CV. No hyphens or em dashes.",
      "CV:\n"+cv+"\n\nTarget Role: "+(target||"general legal roles in Nigeria")
    );
    if(r.startsWith("Error")||r.startsWith("Unable")) setError(r); else setResult(r);
    setLoading(false);
  };
  return (
    <div style={{paddingBottom:80}}>
      <SectionHead title="CV Revamp" sub="Upload your CV and get a polished, hire-ready version instantly."/>

      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(280px,1fr))",gap:24}}>
        <div>
          <div onClick={()=>ref.current.click()} style={{border:`2px dashed ${t.border}`,borderRadius:12,padding:"24px 18px",textAlign:"center",cursor:"pointer",background:t.surface,marginBottom:12,transition:"border-color 0.2s"}} onMouseEnter={e=>e.currentTarget.style.borderColor=CR} onMouseLeave={e=>e.currentTarget.style.borderColor=t.border}>
            <Ic n="upload" s={24} c={t.muted} style={{display:"block",margin:"0 auto 8px"}}/>
            <div style={{fontWeight:700,fontSize:13,color:t.text,marginBottom:2}}>{fn||"Upload your CV"}</div>
            <div style={{fontSize:12,color:t.muted}}>Click to select a .txt or .pdf file</div>
            <input ref={ref} type="file" accept=".txt,.pdf" onChange={handleFile} style={{display:"none"}}/>
          </div>
          {cv&&<div style={{background:"#ECFDF5",border:"1px solid #059669",borderRadius:9,padding:"10px 12px",marginBottom:12,fontSize:12,color:"#065F46",display:"flex",alignItems:"center",gap:6}}><Ic n="check" s={13} c="#059669"/>{fn||"CV pasted"} — ready to revamp.</div>}
          {!cv&&<div style={{marginBottom:12}}><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Or paste your CV text</div><textarea value={cv} onChange={e=>setCv(e.target.value)} placeholder="Paste your CV content here..." rows={6} style={{...inp,resize:"vertical"}}/></div>}
          <div style={{marginBottom:14}}><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Target Role (optional)</div><input style={inp} placeholder="e.g. Compliance Officer, In-House Counsel" value={target} onChange={e=>setTarget(e.target.value)}/></div>
          <button onClick={go} disabled={loading||!cv.trim()} style={{width:"100%",padding:"12px 0",background:loading||!cv.trim()?t.border:`linear-gradient(135deg,${CR},${CRV})`,color:"#fff",border:"none",borderRadius:11,fontSize:13,fontWeight:700,cursor:loading||!cv.trim()?"not-allowed":"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:7}}>
            <Ic n="spark" s={15} c="#fff"/>{loading?"Revamping your CV...":"Revamp My CV"}
          </button>
          {error&&<div style={{marginTop:10,fontSize:12,color:t.sub,background:t.surface,borderRadius:8,padding:"12px 14px",lineHeight:1.6,borderLeft:`3px solid ${CR}`}}>{error}</div>}
        </div>
        <div>
          {!result&&!loading&&<div style={{background:t.surface,border:`2px dashed ${t.border}`,borderRadius:12,minHeight:380,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",color:t.muted,textAlign:"center",padding:24}}><Ic n="file" s={32} c={t.border} style={{marginBottom:12}}/><p style={{fontSize:13,lineHeight:1.7}}>Your revamped CV will appear here. ATS-optimised and professionally structured.</p></div>}
          {loading&&<div style={{background:t.surface,border:`1px solid ${t.border}`,borderRadius:12,minHeight:380,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",color:t.muted}}><Logo size={40}/><p style={{fontSize:13,marginTop:10}}>Polishing your CV...</p></div>}
          {result&&!loading&&<>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
              <span style={{fontWeight:700,fontSize:13,color:t.text}}>Your Revamped CV</span>
              <button onClick={()=>navigator.clipboard.writeText(result)} style={{padding:"6px 12px",background:"transparent",color:CR,border:`1.5px solid ${CR}`,borderRadius:7,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",gap:5}}><Ic n="copy" s={12} c={CR}/>Copy</button>
            </div>
            <div style={{background:t.card,border:`1px solid ${t.border}`,borderRadius:12,padding:"20px 18px",fontSize:13,lineHeight:1.85,color:t.text,whiteSpace:"pre-wrap",fontFamily:"'Georgia',serif",maxHeight:580,overflowY:"auto"}}>{result}</div>
          </>}
        </div>
      </div>
    </div>
  );
}

/* ─── PROFILE ────────────────────────────────────────────────── */
function ProfileTab({ user, updateUser, onLogout, t }) {
  const [editing,setEditing]=useState(false);
  const [loc,setLoc]=useState(user.location||"");
  const fileRef=useRef();const cvRef=useRef();
  const inp={width:"100%",padding:"10px 12px",borderRadius:9,border:`1.5px solid ${t.border}`,fontSize:13,outline:"none",background:t.inputBg,color:t.text,fontFamily:"inherit",boxSizing:"border-box"};
  const handlePhoto=e=>{const file=e.target.files[0];if(!file)return;const r=new FileReader();r.onload=ev=>updateUser({...user,photoUrl:ev.target.result});r.readAsDataURL(file);};
  const handleCV=e=>{const file=e.target.files[0];if(!file)return;const r=new FileReader();r.onload=ev=>updateUser({...user,cvUploaded:true,cvName:file.name,cvText:ev.target.result});r.readAsText(file);};
  const save=()=>{updateUser({...user,location:loc});setEditing(false);};
  const [liMsg,setLiMsg]=useState("");
  const connectLI = async () => {
    const sb = await getSB();
    if (!sb) { setLiMsg("Configure Supabase credentials to enable LinkedIn login."); return; }
    const { error } = await sb.auth.signInWithOAuth({ provider: "linkedin_oidc", options: { redirectTo: window.location.href } });
    if (error) setLiMsg(error.message);
  };
  const levelLabel=user.level==="undergraduate"?"Law Undergraduate":user.level==="fresh"?"Fresh Graduate":"Experienced Lawyer";
  return (
    <div style={{paddingBottom:80,maxWidth:500,margin:"0 auto"}}>
      <SectionHead title="My Profile"/>
      <Card t={t} style={{padding:"28px 24px",marginBottom:14,textAlign:"center"}}>
        <div style={{position:"relative",width:76,height:76,margin:"0 auto 14px"}}>
          <div style={{width:76,height:76,borderRadius:"50%",background:user.photoUrl?"transparent":`linear-gradient(135deg,${CR},${CRV})`,overflow:"hidden",display:"flex",alignItems:"center",justifyContent:"center",fontSize:28,color:"#fff",fontWeight:900,border:`3px solid ${CR}40`}}>
            {user.photoUrl?<img src={user.photoUrl} style={{width:"100%",height:"100%",objectFit:"cover"}} alt=""/>:user.name?.[0]?.toUpperCase()}
          </div>
          <button onClick={()=>fileRef.current.click()} style={{position:"absolute",bottom:0,right:0,width:24,height:24,borderRadius:"50%",background:CR,border:`2px solid ${t.card}`,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}><Ic n="camera" s={12} c="#fff"/></button>
          <input ref={fileRef} type="file" accept="image/*" onChange={handlePhoto} style={{display:"none"}}/>
        </div>
        <div style={{fontWeight:800,fontSize:18,color:t.text,marginBottom:3}}>{user.name}</div>
        <div style={{fontSize:12,color:t.muted,marginBottom:12}}>{user.email}</div>
        <Pill text={levelLabel} color={CR} bg={`${CR}14`}/>
      </Card>
      <Card t={t} style={{padding:"18px 22px",marginBottom:12}}>
        <div style={{fontWeight:700,fontSize:13,color:t.text,marginBottom:12}}>Your CV</div>
        {user.cvUploaded?(
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <div style={{flex:1,fontSize:12,color:t.sub}}><span style={{fontWeight:600}}>{user.cvName}</span> uploaded and active.</div>
            <button onClick={()=>cvRef.current.click()} style={{padding:"7px 12px",fontSize:12,fontWeight:600,border:`1.5px solid ${t.border}`,borderRadius:8,cursor:"pointer",fontFamily:"inherit",background:t.surface,color:t.muted}}>Replace</button>
          </div>
        ):(
          <button onClick={()=>cvRef.current.click()} style={{width:"100%",padding:"11px 0",border:`2px dashed ${t.border}`,borderRadius:10,background:t.surface,cursor:"pointer",fontFamily:"inherit",fontSize:13,fontWeight:600,color:t.muted,display:"flex",alignItems:"center",justifyContent:"center",gap:7}}><Ic n="upload" s={14} c={t.muted}/>Upload CV (.txt or .pdf)</button>
        )}
        <input ref={cvRef} type="file" accept=".txt,.pdf" onChange={handleCV} style={{display:"none"}}/>
      </Card>
      <Card t={t} style={{padding:"18px 22px",marginBottom:12}}>
        <div style={{fontWeight:700,fontSize:13,color:t.text,marginBottom:10}}>Connected Accounts</div>
        {liMsg&&<div style={{fontSize:12,color:"#7C3AED",background:"#EDE9FE",borderRadius:8,padding:"10px 12px",marginBottom:10,lineHeight:1.5}}>{liMsg}</div>}
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <div style={{width:36,height:36,borderRadius:9,background:"#EFF6FF",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Ic n="linkedin" s={18} c="#0A66C2"/></div>
          <div style={{flex:1}}><div style={{fontWeight:600,fontSize:13,color:t.text}}>LinkedIn</div><div style={{fontSize:11,color:t.muted}}>Connect to auto-fill profile and sync applications</div></div>
          <button onClick={connectLI} style={{padding:"8px 14px",background:"#0A66C2",color:"#fff",border:"none",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>Connect</button>
        </div>
      </Card>
      <Card t={t} style={{padding:"18px 22px",marginBottom:12}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
          <div style={{fontWeight:700,fontSize:13,color:t.text}}>Profile Details</div>
          {!editing&&<button onClick={()=>setEditing(true)} style={{fontSize:12,fontWeight:700,color:CR,background:"none",border:"none",cursor:"pointer",fontFamily:"inherit"}}>Edit</button>}
        </div>
        {editing?(
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            <div><div style={{fontSize:11,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Location</div><input style={inp} placeholder="e.g. Lagos, Nigeria" value={loc} onChange={e=>setLoc(e.target.value)}/></div>
            <div style={{display:"flex",gap:8}}>
              <button onClick={()=>setEditing(false)} style={{flex:1,padding:"9px 0",fontSize:13,fontWeight:600,border:`1.5px solid ${t.border}`,borderRadius:9,cursor:"pointer",fontFamily:"inherit",background:"transparent",color:t.muted}}>Cancel</button>
              <button onClick={save} style={{flex:2,padding:"9px 0",fontSize:13,fontWeight:700,border:"none",borderRadius:9,cursor:"pointer",fontFamily:"inherit",background:`linear-gradient(135deg,${CR},${CRV})`,color:"#fff"}}>Save Changes</button>
            </div>
          </div>
        ):(
          [["Name",user.name],["Email",user.email],["Account Type",levelLabel],["Location",user.location||"Not set"]].map(([k,v])=>(
            <div key={k} style={{display:"flex",justifyContent:"space-between",padding:"9px 0",borderBottom:`1px solid ${t.border}`,fontSize:13}}>
              <span style={{color:t.muted}}>{k}</span>
              <span style={{color:t.text,fontWeight:600,textAlign:"right",maxWidth:"60%"}}>{v}</span>
            </div>
          ))
        )}
      </Card>
      <Card t={t} style={{padding:"16px 22px",marginBottom:18}}>
        <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:6}}><Ic n="shield" s={13} c={t.muted}/><span style={{fontWeight:700,fontSize:13,color:t.text}}>Security and Privacy</span></div>
        <p style={{fontSize:12,color:t.muted,lineHeight:1.7,margin:0}}>Your password is encrypted and stored locally on your device only. Esquirely does not transmit or store your credentials on any external server.</p>
      </Card>
      <button onClick={()=>{LS.set("esq_session",null);onLogout();}} style={{width:"100%",padding:"12px 0",background:"#FEF2F2",color:CRL,border:`1.5px solid #FCA5A5`,borderRadius:11,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:7}}>
        <Ic n="logout" s={15} c={CRL}/>Log Out
      </button>
    </div>
  );
}

