      // Fallback to mailto when EmailJS not configured
      window.location.href=`mailto:Boluogunleye1234@gmail.com?subject=${encodeURIComponent(f.subject||"Esquirely: "+f.name)}&body=${encodeURIComponent("From: "+f.name+" ("+f.email+")\n\n"+f.msg)}`;
