              <a href={fd.linkedin} target="_blank" rel="noreferrer" style={{display:"flex",alignItems:"center",justifyContent:"center",gap:5,fontSize:11,color:CR,textDecoration:"none",padding:"6px 0",border:`1px solid ${CR}20`,borderRadius:7,background:`${CR}06`}}><Ic n="linkedin" s={12} c={CR}/>LinkedIn</a>
