            <button onClick={submit} disabled={sending} style={{padding:"12px 0",background:sending?t.border:`linear-gradient(135deg,${CR},${CRV})`,color:"#fff",border:"none",borderRadius:11,fontSize:13,fontWeight:700,cursor:sending?"not-allowed":"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:7,opacity:sending?0.7:1}}><Ic n="send" s={14} c="#fff"/>{sending?"Sending...":"Send Message"}</button>
