/* ─── TAB TRANSITION ─────────────────────────────────────────── */
function TabSlide({ tabKey, children }) {
  const [phase, setPhase] = useState("idle"); // "idle" | "exit" | "enter"
  const [content, setContent] = useState(children);
  const pendingContent = useRef(children);
  const prevKey = useRef(tabKey);

  useEffect(() => {
    if (tabKey === prevKey.current) return;
    prevKey.current = tabKey;
    pendingContent.current = children;
    setPhase("exit");
    const t1 = setTimeout(() => {
      setContent(pendingContent.current);
      setPhase("enter");
    }, 160);
    const t2 = setTimeout(() => setPhase("idle"), 320);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [tabKey]);

  const transform = phase === "exit"  ? "translate3d(-14px,0,0)"
                  : phase === "enter" ? "translate3d(14px,0,0)"
                  : "translate3d(0,0,0)";
  const opacity   = phase === "idle"  ? 1 : 0;

  return (
    <>
      <style>{`.esq-slide{transition:transform 0.16s cubic-bezier(0.25,0.46,0.45,0.94),opacity 0.16s cubic-bezier(0.25,0.46,0.45,0.94);will-change:transform,opacity;}`}</style>
      <div className="esq-slide" style={{ transform, opacity }}>
        {content}
      </div>
    </>
  );
}

/* ─── ROOT ───────────────────────────────────────────────────── */
export default function App() {
  const { dark, setDark, t } = useTheme();
  const [user, setUser]           = useState(null);
  const [loading, setLoading]     = useState(true);
  const [showWelcome, setShowWelcome] = useState(false);
  const [needsLevel, setNeedsLevel]   = useState(false);
  const [tab, setTab]             = useState("Home");

  // ── Auth state listener ──────────────────────────────────────
  useEffect(() => {
    getSB().then(sb => {
      if (!sb) { setLoading(false); return; }
      sb.auth.getSession().then(({ data: { session } }) => {
        if (session?.user) setUser(sbUserToApp(session.user));
        setLoading(false);
      });
      const { data: { subscription } } = sb.auth.onAuthStateChange((_event, session) => {
        if (session?.user) {
          const u = sbUserToApp(session.user);
          setUser(u);
          if (!u.level) setNeedsLevel(true);
        } else {
          setUser(null);
        }
        setLoading(false);
      });
      return () => subscription.unsubscribe();
    });
    if (!SB_CONFIGURED) setLoading(false);
  }, []);

  const handleLogin = useCallback((u) => {
    setUser(u);
    if (!u.level) setNeedsLevel(true);
    else setShowWelcome(true);
  }, []);

  const updateUser = useCallback(async (updated) => {
    setUser(updated);
    const sb = await getSB();
    if (sb) {
      const { cvText, cvName, cvUploaded, photoUrl, location, level, name } = updated;
      // Supabase user_metadata has a ~2KB limit — truncate CV to stay safe
      const safeCv = cvText ? cvText.slice(0, 1800) : "";
      await sb.auth.updateUser({ data: { cvText: safeCv, cvName, cvUploaded, photoUrl, location, level, name } });
    }
  }, []);

  const handleLogout = useCallback(async () => {
    const sb = await getSB();
    if (sb) await sb.auth.signOut();
    setUser(null); setShowWelcome(false); setNeedsLevel(false); setTab("Home");
  }, []);

  // ── Browser back/forward navigation ─────────────────────────
  useEffect(() => {
    if (!user) return;
    const onPop = () => {
      const hash = window.location.hash.replace("#","") || "Home";
      setTab(hash);
    };
    window.addEventListener("popstate", onPop);
    return () => window.removeEventListener("popstate", onPop);
  }, [user]);

  const navigateTo = useCallback((newTab) => {
    setTab(newTab);
    window.history.pushState({tab:newTab}, "", `#${newTab}`);
  }, []);

  // ── Swipe navigation ─────────────────────────────────────────
  const touchStartX = useRef(null);
  useEffect(() => {
    const onTouchStart = (e) => { touchStartX.current = e.touches[0].clientX; };
    const onTouchEnd = (e) => {
      if (touchStartX.current === null) return;
      const dx = e.changedTouches[0].clientX - touchStartX.current;
      if (Math.abs(dx) > 60) { dx > 0 ? window.history.back() : window.history.forward(); }
      touchStartX.current = null;
    };
    document.addEventListener("touchstart", onTouchStart, { passive: true });
    document.addEventListener("touchend",   onTouchEnd,   { passive: true });
    return () => {
      document.removeEventListener("touchstart", onTouchStart);
      document.removeEventListener("touchend",   onTouchEnd);
    };
  }, []);

  // ── Loading splash ───────────────────────────────────────────
  if (loading) return (
    <div style={{minHeight:"100vh",background:t.bg,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:14}}>
      <Logo size={52}/>
      <div style={{fontSize:13,color:t.muted}}>Loading Esquirely...</div>
    </div>
  );

  if (!user)       return <AuthScreen onLogin={handleLogin} t={t}/>;
  if (needsLevel)  return <LevelPicker user={user} onSave={u=>{ setUser(u); setNeedsLevel(false); setShowWelcome(true); }} t={t}/>;
  if (showWelcome) return <WelcomeScreen user={user} onContinue={()=>{ setShowWelcome(false); navigateTo("Home"); }} t={t}/>;

  const tp = { t, updateUser };

  const tabs = {
    Home:                  <HomeTab user={user} setTab={navigateTo} {...tp}/>,
    Jobs:                  <JobsTab user={user} t={t}/>,
    Internships:           <InternshipsTab t={t}/>,
    Scholarships:          <ScholarshipsTab t={t}/>,
    "Application Tracker": <TrackerTab user={user} t={t}/>,
    "Cover Letter":        <CoverLetterTab user={user} t={t}/>,
    "CV Revamp":           <CVRevampTab user={user} t={t} updateUser={updateUser}/>,
    Profile:               <ProfileTab user={user} updateUser={updateUser} onLogout={handleLogout} t={t}/>,
    Contact:               <ContactTab t={t}/>,
    About:                 <AboutTab setTab={navigateTo} t={t}/>,
  };

  return (
    <div style={{fontFamily:"'Helvetica Neue',Helvetica,Arial,sans-serif",background:t.bg,minHeight:"100vh",color:t.text,transition:"background 0.3s,color 0.3s"}}>
      <NavBar active={tab} setTab={navigateTo} user={user} dark={dark} setDark={setDark} onLogout={handleLogout} t={t}/>
      <main style={{maxWidth:1200,margin:"0 auto",padding:"72px 16px 0",overflow:"hidden"}}>
        <TabSlide tabKey={tab}>
          {tabs[tab]||tabs.Home}
        </TabSlide>
      </main>
      <div style={{maxWidth:1200,margin:"0 auto"}}>
        <Footer t={t} setTab={navigateTo}/>
      </div>
    </div>
  );
}
